import java.util.Arrays;

public static long solve(long n, long[][] edges, long k) {
    if (k == n) {
        return 0;
    }
    if (k == 1) {
        return 0;
    }

    // Sort edges by time in ascending order
    Arrays.sort(edges, (a, b) -> Long.compare(a[2], b[2]));

    long left = 0;
    long right = edges.length == 0 ? 0 : edges[edges.length - 1][2];
    long answer = right;

    while (left <= right) {
        long mid = left + (right - left) / 2;
        UnionFind uf = new UnionFind((int) n);
        for (long[] edge : edges) {
            if (edge[2] > mid) {
                uf.union((int) edge[0], (int) edge[1]);
            }
        }
        if (uf.count() >= k) {
            answer = mid;
            right = mid - 1;
        } else {
            left = mid + 1;
        }
    }

    return answer;
}

static class UnionFind {
    private int[] parent;
    private int[] rank;
    private int count;

    public UnionFind(int size) {
        parent = new int[size];
        rank = new int[size];
        count = size;
        for (int i = 0; i < size; i++) {
            parent[i] = i;
            rank[i] = 1;
        }
    }

    public int find(int x) {
        if (parent[x] != x) {
            parent[x] = find(parent[x]);
        }
        return parent[x];
    }

    public void union(int x, int y) {
        int rootX = find(x);
        int rootY = find(y);
        if (rootX != rootY) {
            if (rank[rootX] > rank[rootY]) {
                parent[rootY] = rootX;
            } else if (rank[rootX] < rank[rootY]) {
                parent[rootX] = rootY;
            } else {
                parent[rootY] = rootX;
                rank[rootX]++;
            }
            count--;
        }
    }

    public int count() {
        return count;
