    if (k > n) {
        return -1; // impossible case as per problem constraints
    }

    // Sort edges by time in ascending order
    Arrays.sort(edges, (a, b) -> Long.compare(a[2], b[2]));

    long low = 0;
    long high = edges.length == 0 ? 0 : edges[edges.length - 1][2];
    long answer = high;

    // Binary search to find the minimal t
    while (low <= high) {
        long mid = low + (high - low) / 2;
        UnionFind uf = new UnionFind((int) n);
        for (long[] edge : edges) {
            if (edge[2] > mid) {
                uf.union((int) edge[0], (int) edge[1]);
            }
        }
        if (uf.count() >= k) {
            answer = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    return answer;
